<?php declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';vp3_require_admin_permission('products.view');$pageTitle='Products';require VP3_ROOT.'/includes/admin-header.php';$rows=vp3_db()->query('SELECT id,product_id,name,slug,product_type,current_version,status,self_hosted_enabled,hosted_enabled FROM products ORDER BY name')->fetchAll();?><div class="hero-actions"><h1>Products</h1><a class="button small" href="product.php">New product</a></div><p class="helper">The catalog supports multiple products; Stonefellow is the initial product.</p><div class="table-wrap"><table class="table"><thead><tr><th>Product</th><th>ID</th><th>Type</th><th>Version</th><th>Self-hosted</th><th>Hosted</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $x):?><tr><td><?=vp3_e($x['name'])?></td><td><?=vp3_e($x['product_id'])?></td><td><?=vp3_e($x['product_type'])?></td><td><?=vp3_e($x['current_version'])?></td><td><?=$x['self_hosted_enabled']?'Yes':'No'?></td><td><?=$x['hosted_enabled']?'Yes':'No'?></td><td><span class="badge <?=vp3_e($x['status'])?>"><?=vp3_e($x['status'])?></span></td><td><a href="product.php?id=<?=(int)$x['id']?>">Edit</a></td></tr><?php endforeach;?></tbody></table></div><?php require VP3_ROOT.'/includes/admin-footer.php';?>